function esc(v) { return String(v ?? '').replace(/'/g, "''"); }
const b = $input.first().json;
const acao = String(b.acao ?? '');
return [{ json: {
  projeto_id:   parseInt(b.projeto_id) || 0,
  projeto_nome: esc(b.projeto_nome),
  acao:         esc(acao),
  responsavel:  esc(b.responsavel),
  usuario:      esc(b.usuario || b.responsavel),
  acao_curta:   esc(acao.substring(0, 200))
} }];

