WITH novo AS (
  INSERT INTO claims (projeto_id, projeto_nome, acao, responsavel)
  VALUES ({{ $json.projeto_id }}, '{{ $json.projeto_nome }}', '{{ $json.acao }}', '{{ $json.responsavel }}')
  RETURNING id, projeto_id, projeto_nome, acao, responsavel, status, created_at
), log_ins AS (
  INSERT INTO logs (usuario, acao, entidade, entidade_id, detalhe)
  SELECT '{{ $json.usuario }}', 'ASSUMIU_ACAO', 'claim', id, '{{ $json.acao_curta }}'
  FROM novo
)
SELECT * FROM novo;
